    "id": "catalog-problem-087",
    "titleEn": "",
    "titleZh": "剪绳子",
    "category": "probabilityExpectation",
    "difficulty": "Easy",
    "tags": [
      "Brainteaser 及竞赛型题目",
      "剪绳子"
    ],
    "source": "question-bank",
    "sourceUrl": "Archived Question Bank",
    "sourceType": "book",
    "bookSlug": "question-bank",
    "bookName": "Archived Question Bank",
